function Page() {
  const [user, setUser] = useState(null);
  return <MainSection user={user} setUser={setUser} />;
}
function MainSection({ user, setUser }) {
  return <ContentCard user={user} setUser={setUser} />;
}
function ContentCard({ user, setUser }) {
  return <UserButton user={user} setUser={setUser} />;
}
function UserButton({ user, setUser }) {
  return <button onClick={() => setUser({ name: 'Alice' })}>{user?.name}</button>;
}

const UserContext = createContext();
function Page() {
  const [user, setUser] = useState(null);
  return (
    <UserContext.Provider value={{ user, setUser }}>
      <MainSection />
    </UserContext.Provider>
  );
}
function MainSection() { return <ContentCard />; }
function ContentCard() { return <UserButton />; }
function UserButton() {
  const { user, setUser } = useContext(UserContext);
  return <button onClick={() => setUser({ name: 'Alice' })}>{user?.name}</button>;
}
